import React from "react";
import logo from "../profile.png"; // Your logo image

const Navbar = () => {

  const handleScroll = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav className="fixed w-full top-0 left-0 bg-black bg-opacity-70 backdrop-blur-md z-50">
      <div className="max-w-7xl mx-auto px-6 py-3 flex justify-between items-center">
        {/* Logo */}
        <div className="flex items-center">
          <img src={logo} alt="Logo" className="h-10 w-10 mr-2 rounded-full" />
          <span className="text-white font-bold text-xl">Sindhuja</span>
        </div>

        {/* Navigation Links */}
        <ul className="flex space-x-8 text-white font-semibold">
          <li>
            <button className="hover:text-yellow-400" onClick={() => handleScroll('home')}>
              Home
            </button>
          </li>
          <li>
            <button className="hover:text-yellow-400" onClick={() => handleScroll('about')}>
              About
            </button>
          </li>
          <li>
            <button className="hover:text-yellow-400" onClick={() => handleScroll('projects')}>
              Projects
            </button>
          </li>
          <li>
            <button className="hover:text-yellow-400" onClick={() => handleScroll('contact')}>
              Contact
            </button>
          </li>
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
